using System;
using System.Diagnostics;

public static void GeneratePdfReport(string htmlFilePath, string pdfFilePath, Options options)
{
    // Build the wkhtmltopdf command
    string command = $"wkhtmltopdf --page-size {options.PageSize} --orientation {options.Orientation} {htmlFilePath} {pdfFilePath}";

    // Start the process to execute the command
    ProcessStartInfo startInfo = new ProcessStartInfo("cmd", "/c " + command);
    startInfo.UseShellExecute = false;
    startInfo.RedirectStandardOutput = true;
    startInfo.CreateNoWindow = true;

    using (Process process = Process.Start(startInfo))
    {
        // Wait for the process to exit
        process.WaitForExit();

        // Check if there were any errors
        if (process.ExitCode != 0)
        {
            throw new Exception("Error generating PDF report");
        }
    }
}